# Target shape after replacing SwiftUI with AppKit

Replace the current SwiftUI entry point and menu views:

- remove [`LexApp`](file:///<redacted>/lex/macos/Lex.swift#L5-L20)
- remove [`LexMenuBarLabel`](file:///<redacted>/lex/macos/Lex.swift#L23-L31)
- remove [`AppState`](file:///<redacted>/lex/macos/Lex.swift#L487-L490)
- remove [`LexMenu`](file:///<redacted>/lex/macos/Lex.swift#L492-L503)

The app becomes:

```diagram
╭────────────╮
│  LexMain   │
│ @main      │
╰─────┬──────╯
      │ creates + strongly retains
      ▼
╭─────────────────────╮
│ AppDelegate         │
│ NSApplicationDelegate│
╰─────┬───────────────╯
      │ owns
      ├────────▶ NSStatusItem + NSMenu
      ├────────▶ Zig engine state
      ├────────▶ CGEventTap
      ├────────▶ CGEventSource
      ├────────▶ Carbon hotkey
      ╰────────▶ signal sources
```

The important change: `input_mode` becomes the source of truth, and AppKit UI is updated manually with `update_status_item()` instead of through `ObservableObject` / `@Published`.

# AppKit skeleton

This is the intended shape, not a full drop-in patch.

```swift
import AppKit
import ApplicationServices
import Carbon

// Namespace: LEX!
private let toggle_input_mode_hot_key_id = EventHotKeyID(
    signature: OSType(0x4C455821),
    id: 1
)

// Tag: LEX!
private let synthetic_event_source_user_data: Int64 = 0x4C455821

@main
struct LexMain {
    private static var app_delegate: AppDelegate?

    static func main() {
        let application = NSApplication.shared

        let app_delegate = AppDelegate()
        Self.app_delegate = app_delegate

        application.delegate = app_delegate

        // Info.plist already has LSUIElement=true. This is a fallback if
        // the app is launched without that bundle setting.
        application.setActivationPolicy(.accessory)

        application.run()
    }
}
```

# AppDelegate becomes the whole app shell

```swift
final class AppDelegate: NSObject, NSApplicationDelegate {
    private var status_item: NSStatusItem?

    private lazy var telex_status_image: NSImage? = {
        let image = NSImage(
            systemSymbolName: "pencil",
            accessibilityDescription: "Lex"
        )
        image?.isTemplate = true
        return image
    }()

    private lazy var literal_status_image: NSImage? = {
        let image = NSImage(
            systemSymbolName: "pencil.slash",
            accessibilityDescription: "Lex"
        )
        image?.isTemplate = true
        return image
    }()

    private lazy var telex_sound: NSSound? = NSSound(named: "Pop")
    private lazy var literal_sound: NSSound? = NSSound(named: "Tink")

    private var engine_state: UnsafeMutableRawPointer?
    private var replacement_buffer: [UInt16] = [UInt16](
        repeating: 0,
        count: Int(lex_replacement_buffer_length)
    )
    private var replacement_count: UInt8 = 0

    private var signal_sources: [DispatchSourceSignal] = []
    private var input_mode: InputMode = .telex

    private var toggle_input_mode_hot_key_ref: EventHotKeyRef?
    private var toggle_input_mode_event_handler_ref: EventHandlerRef?

    private var event_tap: CFMachPort?
    private var event_tap_run_loop_source: CFRunLoopSource?
    private var synthetic_event_source: CGEventSource?

    func applicationDidFinishLaunching(_ notification: Notification) {
        initialize_status_item()

        install_signal_handler(SIGINT)
        install_signal_handler(SIGTERM)

        initialize_engine_state()
        initialize_synthetic_event_source()
        start_event_tap()
        register_toggle_input_mode_hot_key()
    }

    func applicationWillTerminate(_ notification: Notification) {
        unregister_toggle_input_mode_hot_key()
        stop_event_tap()
        destroy_synthetic_event_source()
        destroy_engine_state()
        destroy_status_item()
        signal_sources.removeAll()
    }
}
```

# Status item replaces `MenuBarExtra`

```swift
extension AppDelegate {
    private func initialize_status_item() {
        precondition(status_item == nil)

        let status_item = NSStatusBar.system.statusItem(
            withLength: NSStatusItem.squareLength
        )
        self.status_item = status_item

        if let button = status_item.button {
            button.imagePosition = .imageOnly
            button.toolTip = "Lex"
            button.setAccessibilityLabel("Lex")
        }

        let menu = NSMenu()

        let lock_item = NSMenuItem(
            title: "Lock inputs",
            action: #selector(lock_inputs(_:)),
            keyEquivalent: ""
        )
        lock_item.target = self
        menu.addItem(lock_item)

        menu.addItem(.separator())

        let quit_item = NSMenuItem(
            title: "Quit",
            action: #selector(quit(_:)),
            keyEquivalent: "q"
        )
        quit_item.target = self
        menu.addItem(quit_item)

        status_item.menu = menu

        update_status_item()
    }

    private func destroy_status_item() {
        guard let status_item else {
            return
        }

        NSStatusBar.system.removeStatusItem(status_item)
        self.status_item = nil
    }

    private func update_status_item() {
        let image = input_mode == .telex
            ? telex_status_image
            : literal_status_image

        status_item?.button?.image = image
    }

    @objc
    private func lock_inputs(_ sender: Any?) {
        // Preserve current behavior: current SwiftUI "Lock inputs" button is a no-op.
        // If desired later, this can call toggle_input_mode().
    }

    @objc
    private func quit(_ sender: Any?) {
        NSApp.terminate(nil)
    }
}
```

# Mode toggle directly updates AppKit UI

```swift
extension AppDelegate {
    private func toggle_input_mode() {
        input_mode = input_mode == .telex ? .literal : .telex

        reset_engine_state()
        update_status_item()
        play_toggle_sound()
    }

    private func play_toggle_sound() {
        let sound = input_mode == .telex ? telex_sound : literal_sound
        sound?.stop()
        sound?.play()
    }

    func is_literal() -> Bool {
        return input_mode == .literal
    }
}
```

# Carbon hotkey should call the delegate directly

Use the same Carbon hotkey design, but store the handler ref so it can be removed.

```swift
extension AppDelegate {
    private func register_toggle_input_mode_hot_key() {
        let self_pointer = Unmanaged.passUnretained(self).toOpaque()

        var event_type = EventTypeSpec(
            eventClass: OSType(kEventClassKeyboard),
            eventKind: UInt32(kEventHotKeyPressed)
        )

        let install_status = InstallEventHandler(
            GetApplicationEventTarget(),
            { _, event, user_data -> OSStatus in
                guard let user_data else {
                    return OSStatus(eventNotHandledErr)
                }

                var hot_key_id = EventHotKeyID()

                GetEventParameter(
                    event!,
                    EventParamName(kEventParamDirectObject),
                    EventParamType(typeEventHotKeyID),
                    nil,
                    MemoryLayout<EventHotKeyID>.size,
                    nil,
                    &hot_key_id
                )

                guard hot_key_id.signature == toggle_input_mode_hot_key_id.signature,
                      hot_key_id.id == toggle_input_mode_hot_key_id.id
                else {
                    return noErr
                }

                let app_delegate = Unmanaged<AppDelegate>
                    .fromOpaque(user_data)
                    .takeUnretainedValue()

                DispatchQueue.main.async {
                    app_delegate.toggle_input_mode()
                }

                return noErr
            },
            1,
            &event_type,
            self_pointer,
            &toggle_input_mode_event_handler_ref
        )

        guard install_status == noErr else {
            print("Failed to install hotkey event handler: \(install_status)")
            return
        }

        var hot_key_ref: EventHotKeyRef?
        let register_status = RegisterEventHotKey(
            UInt32(kVK_Space),
            UInt32(controlKey | optionKey),
            toggle_input_mode_hot_key_id,
            GetApplicationEventTarget(),
            0,
            &hot_key_ref
        )

        guard register_status == noErr else {
            print("Failed to register hotkey: \(register_status)")
            return
        }

        toggle_input_mode_hot_key_ref = hot_key_ref
    }

    private func unregister_toggle_input_mode_hot_key() {
        if let hot_key_ref = toggle_input_mode_hot_key_ref {
            UnregisterEventHotKey(hot_key_ref)
            toggle_input_mode_hot_key_ref = nil
        }

        if let handler_ref = toggle_input_mode_event_handler_ref {
            RemoveEventHandler(handler_ref)
            toggle_input_mode_event_handler_ref = nil
        }
    }
}
```

# Existing engine and event-tap code mostly stays

Keep these responsibilities inside `AppDelegate`:

```swift
extension AppDelegate {
    private func initialize_engine_state() {
        precondition(engine_state == nil)

        let byte_count = Int(lex_state_size)
        let alignment = Int(lex_state_alignment)

        let state = UnsafeMutableRawPointer.allocate(
            byteCount: byte_count,
            alignment: alignment
        )

        lex_init(state)
        engine_state = state
    }

    private func destroy_engine_state() {
        guard let state = engine_state else {
            return
        }

        state.deallocate()
        engine_state = nil
    }

    func reset_engine_state() {
        lex_init(engine_state)
    }

    func type_character(character: UInt8) {
        lex_add(engine_state, character)
    }

    func type_backspace() {
        if !lex_buffer_empty(engine_state) {
            lex_backspace(engine_state)
        }
    }

    func calculate_synthetic_backspaces() -> UInt8 {
        return lex_calculate_synthetic_backspaces(engine_state)
    }

    func compose_replacement() {
        lex_compose_utf16_string_replacement(
            engine_state,
            &replacement_buffer,
            &replacement_count
        )
    }
}
```

The free C callback shape can stay:

```swift
private func event_tap_callback(
    proxy: CGEventTapProxy,
    type event_type: CGEventType,
    event: CGEvent,
    userInfo: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    guard let userInfo else {
        return Unmanaged.passUnretained(event)
    }

    let app_delegate = Unmanaged<AppDelegate>
        .fromOpaque(userInfo)
        .takeUnretainedValue()

    // Existing event handling logic continues here.
    // It asks AppDelegate for input mode, engine state, synthetic source, etc.
}
```

# Key rewrite rules

1. `AppDelegate` owns the app state. No `ObservableObject`, no `@Published`, no SwiftUI view state.
2. `NSStatusItem` must be strongly retained by `AppDelegate`.
3. `input_mode` changes must call `update_status_item()` manually.
4. Keep `LSUIElement=true` in `Info.plist` so the app remains menu-bar-only.
5. Store and remove the Carbon `EventHandlerRef`.
6. Keep event-tap work minimal; AppKit replacement removes SwiftUI baseline memory, but the event callback should still avoid allocations where possible.

Expected result: lower baseline memory because SwiftUI/AttributeGraph/MenuBarExtra machinery is gone, while AppKit, Swift runtime, Carbon, CoreGraphics, Accessibility, and the Zig engine integration remain.

